"""offlinai_ai — interactive AI coding CLI for the CodeBench shell.

Talks to the Swift-side ``LlamaRunner`` through signal files. Protocol
matches ``offlinai_latex``:

    $TMPDIR/latex_signals/ai_request.json      Python writes, Swift reads + removes
    $TMPDIR/latex_signals/ai_response.stream   Swift appends tokens, Python tails
    $TMPDIR/latex_signals/ai_done.txt          Swift writes status + message
    $TMPDIR/latex_signals/current_editor_file.txt   Swift writes on every file load

The ``ai`` shell builtin opens a persistent REPL:

    $ ai                      # edit whatever file is in the editor
    $ ai path/to/file.py      # edit an explicit file
    ai> add type hints to all functions
    ai> /mode bypass          # auto-apply edits without asking
    ai> /model                # list / select the active GGUF
    ai> /usage                # tokens consumed this session
    ai> /quit                 # exit the REPL

Permission modes:

    nothing   — LLM can read but every write is refused
    allow     — every proposed edit shows a diff and asks y/n (default)
    plan      — LLM writes a multi-step plan, user edits it before any file is touched
    auto      — apply small edits (< 5 lines changed) automatically, large ones prompt
    bypass    — apply everything automatically, no prompts

All writes that actually touch disk also append to an audit log at
``$TMPDIR/latex_signals/ai_audit.log`` so a user can see exactly what
the assistant changed in a session.
"""

from __future__ import annotations

import difflib
import json
import os
import re
import sys
import tempfile
import time
from dataclasses import dataclass, field
from pathlib import Path
from typing import Callable, Iterable, Optional

# ANSI — match offlinai_shell's palette. Kept local so this module can
# be imported independently (e.g. from a one-off script) without pulling
# the full shell in.
_RESET = "\033[0m"
_BOLD  = "\033[1m"
_DIM   = "\033[2m"
_CYN   = "\033[36m"
_GRN   = "\033[32m"
_YLW   = "\033[33m"
_RED   = "\033[31m"
_MAG   = "\033[35m"
_BLU   = "\033[34m"


def _signal_dir() -> Path:
    p = Path(tempfile.gettempdir()) / "latex_signals"
    p.mkdir(parents=True, exist_ok=True)
    return p


# ----------------------------------------------------------------------
# Session state
# ----------------------------------------------------------------------

PermissionMode = str   # one of: "nothing", "allow", "plan", "auto", "bypass"

_MODES = ("nothing", "allow", "plan", "auto", "bypass")
_MODE_HELP = {
    "nothing": "read-only — every write is refused",
    "allow":   "show each edit as a diff, prompt y/n (default)",
    "plan":    "LLM writes a multi-step plan first; user edits it; then apply",
    "auto":    "apply small edits (< 5 lines) automatically, prompt for large",
    "bypass":  "apply every edit automatically, no prompts",
}


@dataclass
class Session:
    target: Optional[Path] = None
    history: list = field(default_factory=list)  # list[(role, content)]
    mode: PermissionMode = "allow"
    total_prompt_tokens: int = 0   # rough estimate — we don't get true counts from LlamaRunner
    total_output_tokens: int = 0
    turns: int = 0
    started_at: float = field(default_factory=time.time)


# ----------------------------------------------------------------------
# LLM bridge
# ----------------------------------------------------------------------

def _write_request(messages: list, max_tokens: int = 2048, stop: Optional[list] = None) -> None:
    """Write ai_request.json atomically (tmp + rename)."""
    sig = _signal_dir()
    payload = {"messages": messages, "max_tokens": max_tokens}
    if stop:
        payload["stop"] = stop
    tmp = sig / "ai_request.json.tmp"
    tmp.write_text(json.dumps(payload), encoding="utf-8")
    tmp.replace(sig / "ai_request.json")


def _clear_response_artifacts() -> None:
    sig = _signal_dir()
    for name in ("ai_response.stream", "ai_done.txt"):
        try:
            (sig / name).unlink()
        except FileNotFoundError:
            pass


def _stream_response(on_token: Callable[[str], None],
                     timeout: float = 300.0) -> tuple[int, str]:
    """Tail ai_response.stream, forwarding each chunk to `on_token`.
    Returns (status, message) when ai_done.txt appears."""
    sig = _signal_dir()
    stream_path = sig / "ai_response.stream"
    done_path = sig / "ai_done.txt"

    # Wait for the stream to exist (Swift truncates-creates it at
    # request pickup). Poll cheaply.
    deadline = time.time() + timeout
    while not stream_path.exists() and time.time() < deadline:
        time.sleep(0.05)

    offset = 0
    while time.time() < deadline:
        try:
            size = stream_path.stat().st_size
        except FileNotFoundError:
            size = 0
        if size > offset:
            with stream_path.open("rb") as fh:
                fh.seek(offset)
                chunk = fh.read(size - offset)
            offset = size
            try:
                on_token(chunk.decode("utf-8", errors="replace"))
            except Exception:
                pass
        if done_path.exists():
            # Drain anything the Swift side appended after the last
            # poll before returning — otherwise the last few tokens
            # of a response get truncated.
            try:
                size = stream_path.stat().st_size
                if size > offset:
                    with stream_path.open("rb") as fh:
                        fh.seek(offset)
                        chunk = fh.read(size - offset)
                    on_token(chunk.decode("utf-8", errors="replace"))
            except Exception:
                pass
            raw = done_path.read_text(encoding="utf-8", errors="replace").splitlines()
            status = int(raw[0]) if raw and raw[0].lstrip("-").isdigit() else -1
            message = raw[1] if len(raw) > 1 else ""
            return status, message
        time.sleep(0.06)
    return -99, "timed out after %.0fs" % timeout


# ----------------------------------------------------------------------
# System prompt
# ----------------------------------------------------------------------

_SYSTEM = """You are a coding assistant inside CodeBench, an on-device development workstation for iPad/iPhone/Mac. You help the user read, reason about, and edit source files.

When proposing a change, always emit the full updated file content in a fenced code block tagged with the language, so the host CLI can apply it as a replace. Example:

```python
# updated contents
...
```

Keep explanations short (< 150 words). If the user only asks a question (no change needed), just answer — don't emit a code block.

If the user's request is ambiguous or dangerous (mass delete, network upload, credentials), ask before acting."""


# ----------------------------------------------------------------------
# Edit extraction + application
# ----------------------------------------------------------------------

_CODE_BLOCK_RE = re.compile(
    r"```(?P<lang>[A-Za-z0-9+_\-]*)\s*\n(?P<body>.*?)```",
    re.DOTALL,
)


def _extract_first_code_block(text: str) -> Optional[tuple[str, str]]:
    m = _CODE_BLOCK_RE.search(text)
    if not m:
        return None
    return m.group("lang").lower(), m.group("body")


def _unified_diff(before: str, after: str, filename: str) -> str:
    return "".join(difflib.unified_diff(
        before.splitlines(keepends=True),
        after.splitlines(keepends=True),
        fromfile=filename + " (before)",
        tofile=filename + " (after)",
        n=2,
    ))


def _confirm(prompt: str) -> bool:
    try:
        ans = input(prompt).strip().lower()
    except (KeyboardInterrupt, EOFError):
        print()
        return False
    return ans in ("y", "yes", "")


def _audit(entry: str) -> None:
    try:
        with (_signal_dir() / "ai_audit.log").open("a", encoding="utf-8") as fh:
            fh.write(f"{time.strftime('%Y-%m-%dT%H:%M:%S')}  {entry}\n")
    except OSError:
        pass


def _apply_edit(session: Session, new_content: str) -> bool:
    """Apply a proposed file replacement per current permission mode.
    Returns True if written to disk."""
    target = session.target
    if target is None:
        print(f"{_RED}  no target file — /file <path> to set one{_RESET}")
        return False

    mode = session.mode
    if mode == "nothing":
        print(f"{_DIM}  [mode=nothing] edit refused. /mode allow to enable.{_RESET}")
        return False

    try:
        before = target.read_text(encoding="utf-8", errors="replace") if target.exists() else ""
    except OSError as e:
        print(f"{_RED}  can't read {target}: {e}{_RESET}")
        return False

    if before == new_content:
        print(f"{_DIM}  (no change){_RESET}")
        return False

    diff = _unified_diff(before, new_content, target.name)
    added = sum(1 for line in diff.splitlines() if line.startswith("+") and not line.startswith("+++"))
    removed = sum(1 for line in diff.splitlines() if line.startswith("-") and not line.startswith("---"))
    total = added + removed

    def _show_diff():
        print(f"\n{_DIM}─── diff for {target.name} (+{added}/-{removed}) ───{_RESET}")
        for line in diff.splitlines():
            if line.startswith("+") and not line.startswith("+++"):
                print(f"{_GRN}{line}{_RESET}")
            elif line.startswith("-") and not line.startswith("---"):
                print(f"{_RED}{line}{_RESET}")
            elif line.startswith("@@"):
                print(f"{_CYN}{line}{_RESET}")
            else:
                print(line)
        print(f"{_DIM}────────────────────────────────────{_RESET}")

    # Decide whether to prompt
    if mode == "bypass":
        do_write = True
    elif mode == "auto":
        if total < 5:
            do_write = True  # small
            print(f"{_DIM}  [mode=auto] auto-applying small edit (+{added}/-{removed}){_RESET}")
        else:
            _show_diff()
            do_write = _confirm(f"{_BOLD}apply? [Y/n] {_RESET}")
    elif mode == "plan":
        # Plan mode would have rejected this before we got here; fall
        # through to allow-style prompt as a safety net.
        _show_diff()
        do_write = _confirm(f"{_BOLD}apply? [Y/n] {_RESET}")
    else:  # "allow"
        _show_diff()
        do_write = _confirm(f"{_BOLD}apply? [Y/n] {_RESET}")

    if not do_write:
        print(f"{_YLW}  skipped.{_RESET}")
        return False

    try:
        target.parent.mkdir(parents=True, exist_ok=True)
        target.write_text(new_content, encoding="utf-8")
    except OSError as e:
        print(f"{_RED}  write failed: {e}{_RESET}")
        return False

    print(f"{_GRN}  ✓ wrote {target}  (+{added}/-{removed}){_RESET}")
    _audit(f"edit {target} +{added}/-{removed} mode={mode}")
    return True


# ----------------------------------------------------------------------
# Slash commands
# ----------------------------------------------------------------------

def _slash_help(session: Session, arg: str) -> None:
    print(f"{_BOLD}Slash commands{_RESET}")
    print(f"  {_CYN}/help{_RESET}            this help")
    print(f"  {_CYN}/quit{_RESET} | /exit | /q     leave the CLI")
    print(f"  {_CYN}/file [<path>]{_RESET}   show or switch the current edit target")
    print(f"  {_CYN}/show [<path>]{_RESET}   print the target (or named file) to the terminal")
    print(f"  {_CYN}/ls [<dir>]{_RESET}      list files in current dir (or given dir)")
    print(f"  {_CYN}/mode [<mode>]{_RESET}   permission mode — one of: {', '.join(_MODES)}")
    print(f"  {_CYN}/model{_RESET}           show the currently-loaded GGUF model")
    print(f"  {_CYN}/usage{_RESET}           tokens + turns this session")
    print(f"  {_CYN}/reset{_RESET}           wipe conversation history")
    print(f"  {_CYN}/clear{_RESET}           clear the terminal screen")
    print()
    print(f"{_BOLD}Anything else{_RESET} is sent to the model as a request about the current file.")


def _slash_file(session: Session, arg: str) -> None:
    if not arg:
        if session.target:
            size = session.target.stat().st_size if session.target.exists() else 0
            print(f"{_DIM}current:{_RESET} {session.target}  {_DIM}({size:,} bytes){_RESET}")
        else:
            print(f"{_DIM}  no target — pass a path: /file path/to/thing.py{_RESET}")
        return
    p = Path(os.path.expanduser(arg)).resolve()
    session.target = p
    if p.exists():
        print(f"{_GRN}  target → {p}{_RESET}")
    else:
        print(f"{_YLW}  target → {p}  (file doesn't exist yet; will be created on first edit){_RESET}")


def _slash_show(session: Session, arg: str) -> None:
    p = Path(os.path.expanduser(arg)).resolve() if arg else session.target
    if p is None:
        print(f"{_RED}  no file{_RESET}"); return
    try:
        content = p.read_text(encoding="utf-8", errors="replace")
    except OSError as e:
        print(f"{_RED}  can't read {p}: {e}{_RESET}"); return
    print(f"{_DIM}─── {p} ───{_RESET}")
    print(content.rstrip())
    print(f"{_DIM}─── end ───{_RESET}")


def _slash_ls(session: Session, arg: str) -> None:
    p = Path(os.path.expanduser(arg)).resolve() if arg else Path.cwd()
    if not p.exists():
        print(f"{_RED}  no such dir: {p}{_RESET}"); return
    for item in sorted(p.iterdir(), key=lambda x: (not x.is_dir(), x.name.lower())):
        if item.name.startswith("."): continue
        mark = "/" if item.is_dir() else ""
        size = "" if item.is_dir() else f"  {_DIM}{item.stat().st_size:>10,}b{_RESET}"
        print(f"  {item.name}{mark}{size}")


def _slash_mode(session: Session, arg: str) -> None:
    if not arg:
        print(f"{_BOLD}current mode:{_RESET} {_CYN}{session.mode}{_RESET} — {_MODE_HELP[session.mode]}")
        print(f"{_DIM}  options:{_RESET}")
        for m in _MODES:
            marker = "● " if m == session.mode else "  "
            print(f"  {marker}{_CYN}{m:<8}{_RESET}  {_MODE_HELP[m]}")
        return
    if arg not in _MODES:
        print(f"{_RED}  unknown mode: {arg}{_RESET}")
        print(f"{_DIM}  valid: {', '.join(_MODES)}{_RESET}")
        return
    old = session.mode
    session.mode = arg
    print(f"{_GRN}  mode:{_RESET} {old} → {_CYN}{arg}{_RESET}  {_DIM}({_MODE_HELP[arg]}){_RESET}")
    _audit(f"mode-change {old} → {arg}")


def _slash_model(session: Session, arg: str) -> None:
    # Ask Swift which model is loaded. We don't have a dedicated
    # current-model signal file yet, so this shows a placeholder.
    # The Swift side can populate $TMPDIR/latex_signals/current_model.txt
    # to surface model name + path + size here.
    p = _signal_dir() / "current_model.txt"
    if p.exists():
        print(p.read_text(encoding="utf-8").rstrip())
    else:
        print(f"{_DIM}  no model published.{_RESET}")
        print(f"{_DIM}  Load a model from the Models tab in the sidebar, then retry.{_RESET}")


def _slash_usage(session: Session, arg: str) -> None:
    elapsed = time.time() - session.started_at
    mins, secs = divmod(int(elapsed), 60)
    print(f"{_BOLD}Session usage{_RESET}")
    print(f"  turns:         {session.turns}")
    print(f"  prompt chars:  {session.total_prompt_tokens:,}  {_DIM}(≈ chars, not tokens){_RESET}")
    print(f"  output chars:  {session.total_output_tokens:,}")
    print(f"  mode:          {session.mode}")
    print(f"  target:        {session.target or '(none)'}")
    print(f"  elapsed:       {mins}m {secs}s")


def _slash_reset(session: Session, arg: str) -> None:
    session.history.clear()
    print(f"{_GRN}  conversation history cleared.{_RESET}")


def _slash_clear(session: Session, arg: str) -> None:
    sys.stdout.write("\033[2J\033[H")
    sys.stdout.flush()


_SLASH = {
    "/help":  _slash_help,
    "/h":     _slash_help,
    "/?":     _slash_help,
    "/quit":  None, "/exit": None, "/q": None,  # handled in loop
    "/file":  _slash_file,
    "/show":  _slash_show,
    "/cat":   _slash_show,
    "/ls":    _slash_ls,
    "/mode":  _slash_mode,
    "/model": _slash_model,
    "/usage": _slash_usage,
    "/reset": _slash_reset,
    "/clear": _slash_clear,
}


# ----------------------------------------------------------------------
# Main entry
# ----------------------------------------------------------------------

def _default_target() -> Optional[Path]:
    """Read the currently-open editor file path from the shared
    signal file that Swift updates on every file load. Empty / missing
    file → None (user will need /file <path>)."""
    p = _signal_dir() / "current_editor_file.txt"
    if not p.exists():
        return None
    txt = p.read_text(encoding="utf-8").strip()
    return Path(txt) if txt else None


def _build_messages(session: Session, user_input: str) -> list[dict]:
    msgs: list[dict] = [{"role": "system", "content": _SYSTEM}]
    msgs.extend(session.history)

    # Current file context
    if session.target and session.target.exists():
        try:
            body = session.target.read_text(encoding="utf-8", errors="replace")
            ext = session.target.suffix.lstrip(".")
            lang_hint = {"py": "python", "swift": "swift", "c": "c", "cpp": "cpp",
                         "cc": "cpp", "h": "c", "hpp": "cpp", "rs": "rust",
                         "go": "go", "ts": "typescript", "js": "javascript",
                         "java": "java", "m": "objectivec", "mm": "objectivec++",
                         "f90": "fortran", "f95": "fortran", "tex": "latex",
                         "md": "markdown", "html": "html", "css": "css",
                         "json": "json", "yaml": "yaml", "sh": "bash"}.get(ext, ext or "")
            msgs.append({
                "role": "user",
                "content": (
                    f"Here is the current content of `{session.target.name}`:\n\n"
                    f"```{lang_hint}\n{body}\n```\n\n"
                    f"{user_input}"
                ),
            })
        except OSError:
            msgs.append({"role": "user", "content": user_input})
    else:
        msgs.append({"role": "user", "content": user_input})
    return msgs


def run(argv: list[str]) -> None:
    """Entry point called by the shell's `ai` builtin."""
    session = Session()

    # Resolve target
    if argv:
        session.target = Path(os.path.expanduser(argv[0])).resolve()
    else:
        session.target = _default_target()

    # Banner
    banner = f"{_MAG}{_BOLD}CodeBench AI{_RESET}  {_DIM}(local model via llama.cpp){_RESET}"
    print(banner)
    if session.target:
        print(f"{_DIM}target:{_RESET} {session.target}")
    else:
        print(f"{_DIM}no current file — use /file <path> to set one{_RESET}")
    print(f"{_DIM}mode:{_RESET} {_CYN}{session.mode}{_RESET}  {_DIM}· /help for commands · /quit to exit{_RESET}")
    print()

    while True:
        try:
            line = input(f"{_CYN}ai>{_RESET} ")
        except EOFError:
            print()
            break
        except KeyboardInterrupt:
            print(f"\n{_YLW}^C  (type /quit to exit){_RESET}")
            continue

        line = line.strip()
        if not line:
            continue
        if line in ("/quit", "/exit", "/q", "exit", "quit"):
            print(f"{_DIM}goodbye — {session.turns} turn{'s' if session.turns != 1 else ''}{_RESET}")
            break

        # Slash command dispatch
        if line.startswith("/"):
            parts = line.split(None, 1)
            cmd = parts[0]
            arg = parts[1] if len(parts) > 1 else ""
            handler = _SLASH.get(cmd)
            if handler is None:
                print(f"{_RED}unknown command: {cmd}{_RESET}  {_DIM}— /help for list{_RESET}")
            else:
                handler(session, arg)
            continue

        # Plan mode: two-step interaction
        if session.mode == "plan":
            _run_plan_mode(session, line)
        else:
            _run_normal_turn(session, line)

    print()


def _run_normal_turn(session: Session, user_input: str) -> None:
    messages = _build_messages(session, user_input)
    session.total_prompt_tokens += sum(len(m["content"]) for m in messages)
    session.turns += 1

    _clear_response_artifacts()
    _write_request(messages, max_tokens=2048)

    print()  # blank line before response
    collected: list[str] = []
    def on_token(chunk: str) -> None:
        sys.stdout.write(chunk)
        sys.stdout.flush()
        collected.append(chunk)

    status, message = _stream_response(on_token, timeout=600.0)
    print()  # newline after response

    if status != 0:
        print(f"{_RED}  [error {status}]{_RESET} {message}")
        return

    full = "".join(collected)
    session.total_output_tokens += len(full)
    session.history.append({"role": "user", "content": user_input})
    session.history.append({"role": "assistant", "content": full})

    # Look for a code block to apply
    block = _extract_first_code_block(full)
    if block is not None:
        _lang, body = block
        # Only treat as an edit if the block looks like complete code,
        # not a short snippet quote. Heuristic: >= 80% of the original
        # file's lines OR >= 10 lines total.
        lines = body.count("\n")
        if lines >= 10 or (session.target and session.target.exists()
                           and body.count("\n") >= session.target.read_text(errors="replace").count("\n") * 0.5):
            _apply_edit(session, body)


def _run_plan_mode(session: Session, user_input: str) -> None:
    """Plan-first workflow: ask for a plan, let user edit it, then execute."""
    plan_prompt = (
        f"Plan mode: before writing any code, produce a numbered plan of steps you'd "
        f"take to accomplish this request. Do NOT include code blocks yet. Request:\n\n"
        f"{user_input}"
    )
    messages = _build_messages(session, plan_prompt)
    session.turns += 1
    _clear_response_artifacts()
    _write_request(messages, max_tokens=1024)

    print()
    buf: list[str] = []
    def on_token(chunk: str) -> None:
        sys.stdout.write(chunk); sys.stdout.flush(); buf.append(chunk)
    status, msg = _stream_response(on_token, timeout=300.0)
    print()
    if status != 0:
        print(f"{_RED}  [plan error {status}]{_RESET} {msg}"); return

    plan_text = "".join(buf)
    session.history.append({"role": "user", "content": plan_prompt})
    session.history.append({"role": "assistant", "content": plan_text})

    print(f"\n{_DIM}─── edit the plan (blank line or Ctrl+D to submit; /cancel to abort) ───{_RESET}")
    try:
        edited_lines: list[str] = []
        while True:
            try:
                piece = input("> ")
            except EOFError:
                break
            if piece == "/cancel":
                print(f"{_YLW}  plan cancelled.{_RESET}")
                return
            if not piece and edited_lines:
                break
            edited_lines.append(piece)
        final_plan = "\n".join(edited_lines).strip() or plan_text
    except KeyboardInterrupt:
        print(f"\n{_YLW}  plan cancelled.{_RESET}"); return

    # Execute: ask for the code in allow-mode for the apply step
    exec_prompt = (
        f"Execute this plan. Produce the full updated file content in a single "
        f"fenced code block tagged with the language.\n\nPlan:\n{final_plan}"
    )
    old_mode = session.mode
    session.mode = "allow"
    try:
        _run_normal_turn(session, exec_prompt)
    finally:
        session.mode = old_mode
